import{_ as g,C as o,o as l,c as E,a5 as a,b as s,w as e,a as d,E as r,a4 as i}from"./chunks/framework.sOZL8giL.js";const c=JSON.parse('{"title":"上下文工程速查","description":"","frontmatter":{},"headers":[],"relativePath":"02-上下文工程/速查.md","filePath":"02-上下文工程/速查.md","lastUpdated":null}'),f={name:"02-上下文工程/速查.md"};function x(y,t,h,B,A,b){const n=o("Mermaid");return l(),E("div",null,[t[2]||(t[2]=a(`<h1 id="上下文工程速查" tabindex="-1">上下文工程速查 <a class="header-anchor" href="#上下文工程速查" aria-label="Permalink to &quot;上下文工程速查&quot;">​</a></h1><blockquote><p>快速查阅上下文管理的策略选择、适用场景和常见问题解决方案。</p></blockquote><hr><h2 id="一、核心概念速查" tabindex="-1">一、核心概念速查 <a class="header-anchor" href="#一、核心概念速查" aria-label="Permalink to &quot;一、核心概念速查&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">概念</th><th style="text-align:left;">定义</th><th style="text-align:left;">一句话理解</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>上下文工程</strong></td><td style="text-align:left;">为 Agent 动态管理其完整信息视野的架构学科</td><td style="text-align:left;">从&quot;写好一句 Prompt&quot;变成&quot;设计整个信息环境&quot;</td></tr><tr><td style="text-align:left;"><strong>上下文腐烂</strong></td><td style="text-align:left;">上下文越长，模型回忆和推理能力平滑下降</td><td style="text-align:left;">信息越多，AI 越容易&quot;失焦&quot;</td></tr><tr><td style="text-align:left;"><strong>上下文债务</strong></td><td style="text-align:left;">Agent 循环中不断累积的、未经管理的信息</td><td style="text-align:left;">像信用卡债务，不还会利滚利</td></tr></tbody></table><hr><h2 id="二、三大支柱速查表" tabindex="-1">二、三大支柱速查表 <a class="header-anchor" href="#二、三大支柱速查表" aria-label="Permalink to &quot;二、三大支柱速查表&quot;">​</a></h2><p><strong>核心问题：什么时候用卸载 vs 缩减 vs 隔离？</strong></p><table tabindex="0"><thead><tr><th style="text-align:left;">支柱</th><th style="text-align:left;">核心思想</th><th style="text-align:left;">适用场景</th><th style="text-align:left;">典型实现</th><th style="text-align:left;">代价</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>卸载 (Offloading)</strong></td><td style="text-align:left;">将上下文从 LLM 窗口转移到外部存储</td><td style="text-align:left;">工具太多塞不下、信息需要跨会话保留</td><td style="text-align:left;">文件系统、分层行动空间、渐进式披露</td><td style="text-align:left;">增加外部存储和检索复杂度</td></tr><tr><td style="text-align:left;"><strong>缩减 (Reduction)</strong></td><td style="text-align:left;">减小每步传递给模型的上下文大小</td><td style="text-align:left;">上下文接近极限、历史信息过时</td><td style="text-align:left;">压缩（指针替换）、摘要（结构化摘要）</td><td style="text-align:left;">可能丢失信息（尤其摘要不可逆）</td></tr><tr><td style="text-align:left;"><strong>隔离 (Isolation)</strong></td><td style="text-align:left;">不同任务使用独立上下文窗口</td><td style="text-align:left;">子任务独立、需要干净上下文</td><td style="text-align:left;">子 Agent、通信/共享上下文模式</td><td style="text-align:left;">协调成本、Token 消耗增加</td></tr></tbody></table><hr><h2 id="三、卸载策略详解" tabindex="-1">三、卸载策略详解 <a class="header-anchor" href="#三、卸载策略详解" aria-label="Permalink to &quot;三、卸载策略详解&quot;">​</a></h2><h3 id="_3-1-卸载数据-文件系统即上下文" tabindex="-1">3.1 卸载数据：文件系统即上下文 <a class="header-anchor" href="#_3-1-卸载数据-文件系统即上下文" aria-label="Permalink to &quot;3.1 卸载数据：文件系统即上下文&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">场景</th><th style="text-align:left;">做法</th><th style="text-align:left;">价值</th></tr></thead><tbody><tr><td style="text-align:left;">对抗目标漂移</td><td style="text-align:left;">Agent 将计划写入文件，执行中定期读回</td><td style="text-align:left;">确保不偏离目标</td></tr><tr><td style="text-align:left;">跨会话记忆</td><td style="text-align:left;"><code>CLAUDE.md</code> / <code>.cursor/</code> 文件持久化用户偏好</td><td style="text-align:left;">零部署、版本控制友好</td></tr><tr><td style="text-align:left;">知识库扩展</td><td style="text-align:left;">结构化目录（<code>dox/</code>），Agent 自主探索</td><td style="text-align:left;">知识可无限增长</td></tr></tbody></table><h3 id="_3-2-卸载工具-分层行动空间" tabindex="-1">3.2 卸载工具：分层行动空间 <a class="header-anchor" href="#_3-2-卸载工具-分层行动空间" aria-label="Permalink to &quot;3.2 卸载工具：分层行动空间&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────┐</span></span>
<span class="line"><span>│  第三层：包和 API（编写和执行代码）        │  ← 最开放、能力最强</span></span>
<span class="line"><span>└─────────────────────────────────────────┘</span></span>
<span class="line"><span>                    ↑ 通过第一层函数调用</span></span>
<span class="line"><span>┌─────────────────────────────────────────┐</span></span>
<span class="line"><span>│  第二层：沙盒使用程序（命令行程序）        │  ← 能力扩展的主要层面</span></span>
<span class="line"><span>└─────────────────────────────────────────┘</span></span>
<span class="line"><span>                    ↑ 通过第一层函数调用</span></span>
<span class="line"><span>┌─────────────────────────────────────────┐</span></span>
<span class="line"><span>│  第一层：函数调用（原子操作）              │  ← 与模型直接交互的唯一一层</span></span>
<span class="line"><span>└─────────────────────────────────────────┘</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><table tabindex="0"><thead><tr><th style="text-align:left;">层级</th><th style="text-align:left;">设计原则</th><th style="text-align:left;">顶级 Agent 的工具数</th></tr></thead><tbody><tr><td style="text-align:left;">第一层</td><td style="text-align:left;">极简、固定不变、KV 缓存友好</td><td style="text-align:left;">Claude Code ~12个，Menlo &lt;20个</td></tr><tr><td style="text-align:left;">第二层</td><td style="text-align:left;">预装在沙盒中的命令行工具</td><td style="text-align:left;">通过 bash 自主发现</td></tr><tr><td style="text-align:left;">第三层</td><td style="text-align:left;">编写脚本调用任意 API</td><td style="text-align:left;">无上限</td></tr></tbody></table><h3 id="_3-3-渐进式披露" tabindex="-1">3.3 渐进式披露 <a class="header-anchor" href="#_3-3-渐进式披露" aria-label="Permalink to &quot;3.3 渐进式披露&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">层级</th><th style="text-align:left;">内容</th><th style="text-align:left;">Token 消耗</th><th style="text-align:left;">加载方式</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Level 1</strong></td><td style="text-align:left;">技能名称 + 简介（YAML Front Matter）</td><td style="text-align:left;">~100</td><td style="text-align:left;">始终加载</td></tr><tr><td style="text-align:left;"><strong>Level 2</strong></td><td style="text-align:left;">核心指令与 SOP（Markdown 正文）</td><td style="text-align:left;">&lt;5,000</td><td style="text-align:left;">触发时加载</td></tr><tr><td style="text-align:left;"><strong>Level 3+</strong></td><td style="text-align:left;">详细文档、脚本、配置</td><td style="text-align:left;">无上限</td><td style="text-align:left;">按需加载</td></tr></tbody></table><p><strong>关键洞察</strong>：模型并不扩大上下文窗口，而是通过外部化执行让技能包的体积与上下文无关。</p><hr><h2 id="四、缩减策略详解" tabindex="-1">四、缩减策略详解 <a class="header-anchor" href="#四、缩减策略详解" aria-label="Permalink to &quot;四、缩减策略详解&quot;">​</a></h2><h3 id="_4-1-压缩-vs-摘要对比" tabindex="-1">4.1 压缩 vs 摘要对比 <a class="header-anchor" href="#_4-1-压缩-vs-摘要对比" aria-label="Permalink to &quot;4.1 压缩 vs 摘要对比&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">维度</th><th style="text-align:left;">压缩 (Compression)</th><th style="text-align:left;">摘要 (Summarization)</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>可逆性</strong></td><td style="text-align:left;">✅ 可逆</td><td style="text-align:left;">❌ 不可逆</td></tr><tr><td style="text-align:left;"><strong>做法</strong></td><td style="text-align:left;">完整内容卸载到文件，消息历史中用指针替换</td><td style="text-align:left;">生成结构化摘要替代原始内容</td></tr><tr><td style="text-align:left;"><strong>适用时机</strong></td><td style="text-align:left;">工具结果变得陈旧时</td><td style="text-align:left;">上下文接近极限（如 95%）时</td></tr><tr><td style="text-align:left;"><strong>信息保真度</strong></td><td style="text-align:left;">100%（可随时恢复）</td><td style="text-align:left;">取决于摘要质量</td></tr><tr><td style="text-align:left;"><strong>最佳实践</strong></td><td style="text-align:left;">优先使用</td><td style="text-align:left;">仅在压缩收益变小时才启用</td></tr></tbody></table><h3 id="_4-2-摘要最佳实践" tabindex="-1">4.2 摘要最佳实践 <a class="header-anchor" href="#_4-2-摘要最佳实践" aria-label="Permalink to &quot;4.2 摘要最佳实践&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">原则</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>结构化 Schema</strong></td><td style="text-align:left;">用&quot;填表&quot;而非自由格式，保证关键信息不丢失</td></tr><tr><td style="text-align:left;"><strong>优先级排序</strong></td><td style="text-align:left;">先摘要最不重要的信息，保留核心上下文</td></tr><tr><td style="text-align:left;"><strong>触发条件</strong></td><td style="text-align:left;">仅在上下文接近极限时才启用（别太早用）</td></tr></tbody></table><hr><h2 id="五、隔离策略详解" tabindex="-1">五、隔离策略详解 <a class="header-anchor" href="#五、隔离策略详解" aria-label="Permalink to &quot;五、隔离策略详解&quot;">​</a></h2><h3 id="两种隔离模式对比" tabindex="-1">两种隔离模式对比 <a class="header-anchor" href="#两种隔离模式对比" aria-label="Permalink to &quot;两种隔离模式对比&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">维度</th><th style="text-align:left;">通过通信 (By Communication)</th><th style="text-align:left;">通过共享上下文 (By Shared Context)</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>工作方式</strong></td><td style="text-align:left;">主 Agent 传简短指令，子 Agent 在干净上下文中完成，仅返回结果</td><td style="text-align:left;">子 Agent 访问主 Agent 完整历史，但使用新 System Prompt</td></tr><tr><td style="text-align:left;"><strong>适用场景</strong></td><td style="text-align:left;">可清晰切分的简单任务</td><td style="text-align:left;">需要完整历史视野的复杂任务</td></tr><tr><td style="text-align:left;"><strong>成本</strong></td><td style="text-align:left;">低（KV 缓存友好）</td><td style="text-align:left;">极高（KV 缓存完全失效）</td></tr><tr><td style="text-align:left;"><strong>延迟</strong></td><td style="text-align:left;">低</td><td style="text-align:left;">高</td></tr><tr><td style="text-align:left;"><strong>选择标准</strong></td><td style="text-align:left;">任务是否需要之前所有上下文？</td><td style="text-align:left;">任务是否必须基于完整历史决策？</td></tr></tbody></table><hr><h2 id="六、上下文失效的四种模式速查" tabindex="-1">六、上下文失效的四种模式速查 <a class="header-anchor" href="#六、上下文失效的四种模式速查" aria-label="Permalink to &quot;六、上下文失效的四种模式速查&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">模式</th><th style="text-align:left;">定义</th><th style="text-align:left;">比喻</th><th style="text-align:left;">诊断信号</th><th style="text-align:left;">解法</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>污染 (Contamination)</strong></td><td style="text-align:left;">幻觉/错误信息渗入上下文，被后续推理当事实</td><td style="text-align:left;">信息源被投毒</td><td style="text-align:left;">输出基于错误前提推导出荒谬结论</td><td style="text-align:left;">验证关键事实来源；保留错误信息供学习</td></tr><tr><td style="text-align:left;"><strong>干扰 (Interference)</strong></td><td style="text-align:left;">信息过多，压倒模型预训练知识</td><td style="text-align:left;">信噪比过低</td><td style="text-align:left;">模型做出违背常识的判断</td><td style="text-align:left;">缩减上下文；优先保留高价值信息</td></tr><tr><td style="text-align:left;"><strong>混淆 (Confusion)</strong></td><td style="text-align:left;">多余的不相关信息影响最终回应</td><td style="text-align:left;">注意力被分散</td><td style="text-align:left;">把两个不相关概念错误关联</td><td style="text-align:left;">隔离上下文；精简不相关内容</td></tr><tr><td style="text-align:left;"><strong>冲突 (Conflict)</strong></td><td style="text-align:left;">不同部分包含相互矛盾的信息</td><td style="text-align:left;">指令集冲突</td><td style="text-align:left;">模型犹豫不决或行为混乱</td><td style="text-align:left;">统一信息源；消解矛盾</td></tr></tbody></table><h3 id="与上下文腐烂的因果关系" tabindex="-1">与上下文腐烂的因果关系 <a class="header-anchor" href="#与上下文腐烂的因果关系" aria-label="Permalink to &quot;与上下文腐烂的因果关系&quot;">​</a></h3>`,33)),(l(),s(i,null,{default:e(()=>[r(n,{id:"mermaid-619",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20A%5B%E4%B8%8A%E4%B8%8B%E6%96%87%E8%85%90%E7%83%82%3Cbr%2F%3E%E5%BA%95%E5%B1%82%E7%8A%B6%E6%80%81%5D%20--%3E%20B%5B%E6%B3%A8%E6%84%8F%E5%8A%9B%E7%A8%80%E9%87%8A%3Cbr%2F%3E%E4%BF%A1%E5%99%AA%E6%AF%94%E9%99%8D%E4%BD%8E%5D%0A%20%20%20%20B%20--%3E%20C%5B%E7%9B%B4%E6%8E%A5%E5%BC%95%E5%8F%91%EF%BC%9A%E5%B9%B2%E6%89%B0%20%26%20%E6%B7%B7%E6%B7%86%5D%0A%20%20%20%20A%20--%3E%20D%5B%E6%8E%A8%E7%90%86%E8%83%BD%E5%8A%9B%E4%B8%8B%E9%99%8D%5D%0A%20%20%20%20D%20--%3E%20E%5B%E5%82%AC%E7%94%9F%EF%BC%9A%E6%B1%A1%E6%9F%93%3Cbr%2F%3E%E6%9B%B4%E5%AE%B9%E6%98%93%E4%BA%A7%E7%94%9F%E5%B9%BB%E8%A7%89%5D%0A%20%20%20%20A%20--%3E%20F%5B%E9%95%BF%E8%B7%9D%E7%A6%BB%E8%AE%B0%E5%BF%86%E8%A1%B0%E9%80%80%5D%0A%20%20%20%20F%20--%3E%20G%5B%E5%B1%8F%E8%94%BD%E5%8F%91%E7%8E%B0%EF%BC%9A%E5%86%B2%E7%AA%81%3Cbr%2F%3E%E5%8F%91%E7%8E%B0%E4%B8%8D%E4%BA%86%E8%BF%9C%E5%A4%84%E7%9A%84%E7%9F%9B%E7%9B%BE%E4%BF%A1%E6%81%AF%5D%0A"})]),fallback:e(()=>[...t[0]||(t[0]=[d(" Loading... ",-1)])]),_:1})),t[3]||(t[3]=a('<hr><h2 id="七、常见的上下文问题-→-解法速查" tabindex="-1">七、常见的上下文问题 → 解法速查 <a class="header-anchor" href="#七、常见的上下文问题-→-解法速查" aria-label="Permalink to &quot;七、常见的上下文问题 → 解法速查&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">问题</th><th style="text-align:left;">症状</th><th style="text-align:left;">推荐策略</th></tr></thead><tbody><tr><td style="text-align:left;">Agent 在长任务中忘记目标</td><td style="text-align:left;">执行到一半偏离原始计划</td><td style="text-align:left;"><strong>卸载</strong>：将计划写入文件，定期读回</td></tr><tr><td style="text-align:left;">工具太多导致调用错误</td><td style="text-align:left;">Agent 调用了错误的工具或不存在的工具</td><td style="text-align:left;"><strong>卸载</strong>：分层行动空间，极简第一层</td></tr><tr><td style="text-align:left;">上下文窗口快满了</td><td style="text-align:left;">Token 消耗急剧上升</td><td style="text-align:left;"><strong>缩减</strong>：压缩（先）→ 摘要（后）</td></tr><tr><td style="text-align:left;">子任务需要干净上下文</td><td style="text-align:left;">子任务结果被历史信息干扰</td><td style="text-align:left;"><strong>隔离</strong>：子 Agent + 通信模式</td></tr><tr><td style="text-align:left;">Agent 重复搜索同一信息</td><td style="text-align:left;">多轮对话中反复查询</td><td style="text-align:left;"><strong>卸载</strong>：文件系统记忆 + 渐进式披露</td></tr><tr><td style="text-align:left;">不同来源信息矛盾</td><td style="text-align:left;">模型犹豫不决</td><td style="text-align:left;"><strong>隔离</strong>：为不同来源建立独立评估路径</td></tr><tr><td style="text-align:left;">输出质量随对话变长下降</td><td style="text-align:left;">越聊越&quot;傻&quot;</td><td style="text-align:left;"><strong>缩减</strong>：适时摘要 + <strong>隔离</strong>：复杂子任务独立处理</td></tr></tbody></table><hr><h2 id="八、选型决策流程图" tabindex="-1">八、选型决策流程图 <a class="header-anchor" href="#八、选型决策流程图" aria-label="Permalink to &quot;八、选型决策流程图&quot;">​</a></h2>',5)),(l(),s(i,null,{default:e(()=>[r(n,{id:"mermaid-722",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20A%5BAgent%20%E4%B8%8A%E4%B8%8B%E6%96%87%E7%AE%A1%E7%90%86%E9%97%AE%E9%A2%98%5D%20--%3E%20B%7B%E9%97%AE%E9%A2%98%E7%B1%BB%E5%9E%8B%EF%BC%9F%7D%0A%20%20%20%20B%20--%3E%7C%E5%B7%A5%E5%85%B7%E5%A4%AA%E5%A4%9A%7C%20C%5B%E5%8D%B8%E8%BD%BD%EF%BC%9A%E5%88%86%E5%B1%82%E8%A1%8C%E5%8A%A8%E7%A9%BA%E9%97%B4%5D%0A%20%20%20%20B%20--%3E%7C%E4%BF%A1%E6%81%AF%E4%BF%9D%E7%95%99%7C%20D%5B%E5%8D%B8%E8%BD%BD%EF%BC%9A%E6%96%87%E4%BB%B6%E7%B3%BB%E7%BB%9F%E8%AE%B0%E5%BF%86%5D%0A%20%20%20%20B%20--%3E%7C%E4%B8%8A%E4%B8%8B%E6%96%87%E5%B0%86%E6%BB%A1%7C%20E%7B%E4%BF%A1%E6%81%AF%E6%98%AF%E5%90%A6%E5%8F%AF%E9%80%86%EF%BC%9F%7D%0A%20%20%20%20B%20--%3E%7C%E5%AD%90%E4%BB%BB%E5%8A%A1%E5%B9%B2%E6%89%B0%7C%20F%5B%E9%9A%94%E7%A6%BB%EF%BC%9A%E5%AD%90%20Agent%5D%0A%20%20%20%20B%20--%3E%7C%E4%BF%A1%E6%81%AF%E5%86%B2%E7%AA%81%2F%E6%B7%B7%E4%B9%B1%7C%20G%7B%E8%83%BD%E5%90%A6%E7%BB%9F%E4%B8%80%E4%BF%A1%E6%81%AF%E6%BA%90%EF%BC%9F%7D%0A%0A%20%20%20%20E%20--%3E%7C%E6%98%AF%7C%20E1%5B%E5%8E%8B%E7%BC%A9%EF%BC%9A%E6%8C%87%E9%92%88%E6%9B%BF%E6%8D%A2%5D%0A%20%20%20%20E%20--%3E%7C%E5%90%A6%7C%20E2%5B%E6%91%98%E8%A6%81%EF%BC%9A%E7%BB%93%E6%9E%84%E5%8C%96%20Schema%5D%0A%0A%20%20%20%20G%20--%3E%7C%E6%98%AF%7C%20G1%5B%E5%90%88%E5%B9%B6%2F%E5%8E%BB%E9%87%8D%5D%0A%20%20%20%20G%20--%3E%7C%E5%90%A6%7C%20G2%5B%E9%9A%94%E7%A6%BB%EF%BC%9A%E7%8B%AC%E7%AB%8B%E8%AF%84%E4%BC%B0%E8%B7%AF%E5%BE%84%5D%0A"})]),fallback:e(()=>[...t[1]||(t[1]=[d(" Loading... ",-1)])]),_:1})),t[4]||(t[4]=a('<hr><h2 id="九、menlo-的实战经验速查" tabindex="-1">九、Menlo 的实战经验速查 <a class="header-anchor" href="#九、menlo-的实战经验速查" aria-label="Permalink to &quot;九、Menlo 的实战经验速查&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">经验</th><th style="text-align:left;">教训</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>遮蔽而非移除</strong></td><td style="text-align:left;">不要在运行时动态加载/卸载工具（破坏 KV 缓存）</td></tr><tr><td style="text-align:left;"><strong>文件系统即上下文</strong></td><td style="text-align:left;">当上下文装不下时，给 Agent 一个文件系统</td></tr><tr><td style="text-align:left;"><strong>工具集固定</strong></td><td style="text-align:left;">顶级 Agent 的原生工具集都极少（&lt;20个）</td></tr><tr><td style="text-align:left;"><strong>渐进式披露</strong></td><td style="text-align:left;">连脚本也不必一开始就全部告知模型</td></tr><tr><td style="text-align:left;"><strong>保留错误信息</strong></td><td style="text-align:left;">让 Agent 从失败中学习</td></tr></tbody></table>',3))])}const u=g(f,[["render",x]]);export{c as __pageData,u as default};
